es": {"human": 0.999960549989411, "ai": 2.7689068021218702e-05, "paraphrased": 1.1760942567772586e-05}, "interpretability_value": null, "interpretability_normalized_value": null, "interpretability_designation": null, "interpretability_alpha": null, "highlight_sentence_for_ai": false, "special_highlight_type": null}, {"generated_prob": 3.9088668373743953e-05, "sentence": "Right after he got them out, his energy level went way up, even for a senior pup.", "perplexity": 0, "class_probabilities": {"human": 0.9999609113316262, "ai": 2.6871365509309523e-05, "paraphrased": 1.221730286443443e-05}, "interpretability_value": null, "interpretability_normalized_value": null, "interpretability_designation": null, "interpretability_alpha": null, "highlight_sentence_for_ai": false, "special_highlight_type": null}, {"generated_prob": 3.0896340178543006e-05, "sentence": "However there has been a bit of a problem since he is such a hood rat, he likes getting into my groceries.", "perplexity": 0, "class_probabilities": {"human": 0.9999691036598215, "ai": 1.5529463452481947e-05, "paraphrased": 1.5366876726061055e-05}, "interpretability_value": null, "interpretability_normalized_value": null, "interpretability_designation": null, "interpretability_alpha": null, "highlight_sentence_for_ai": false, "special_highlight_type": null}, {"generated_prob": 3.1731711015721626e-05, "sentence": "About once a week, I like to get us a steak to share.", "perplexity": 0, "class_probabilities": {"human": 0.9999682682889843, "ai": 1.5495602951413783e-05, "paraphrased": 1.6236108064307843e-05}, "interpretability_value": null, "interpretability_normalized_value": null, "interpretability_designation": null, "interpretability_alpha": null, "highlight_sentence_for_ai": false, "special_highlight_type": null}, {"generated_prob": 3.384045754266482e-05, "sentence": "It's not very expensive, and usually comes with sides.", "perplexity": 0, "class_probabilities": {"human": 0.9999661595424574, "ai": 1.7118220313906317e-05, "paraphrased": 1.6722237228758505e-05}, "interpretability_value": null, "interpretability_normalized_value": null, "interpretability_designation": null, "interpretability_alpha": null, "highlight_sentence_for_ai": false, "special_highlight_type": null}, {"generated_prob": 3.288898593572435e-05, "sentence": "It comes in an oven-ready tray so you can just pop it in the oven.", "perplexity": 0, "class_probabilities": {"human": 0.9999671110140643, "ai": 1.5344616454596565e-05, "paraphrased": 1.7544369481127788e-05}, "interpretability_value": null, "interpretability_normalized_value": null, "interpretability_designation": null, "interpretability_alpha": null, "highlight_sentence_for_ai": false, "special_highlight_type": null}, {"generated_prob": 3.222902932353823e-05, "sentence": "However, my dog has learned how to get into the grocery bag, claw open the plastic wrap covering, and pull out the steak.", "perplexity": 0, "class_probabilities": {"human": 0.9999677709706765, "ai": 1.5295315538317316e-05, "paraphrased": 1.693371378522092e-05}, "interpretability_value": null, "interpretability_normalized_value": null, "interpretability_designation": null, "interpretability_alpha": null, "highlight_sentence_for_ai": false, "special_highlight_type": null}, {"generated_prob": 3.228756090228568e-05, "sentence": "Unfortunately for him (fortunately for me), since he has zero teeth, he has been unable to do anything about it once he gets the steak out of the packaging.", "perplexity": 0, "class_probabilities": {"human": 0.9999677124390978, "ai": 1.510380416360235e-05, "paraphrased": 1.718375673868333e-05}, "interpretability_value": null, "interpretability_normalized_value": null, "interpretability_designation": null, "interpretability_alpha": null, "highlight_sentence_for_ai": false, "special_highlight_type": null}, {"generated_prob": 3.4566987906928694e-05, "sentence": "Saddest dog ever.", "perplexity": 0, "class_probabilities": {"human": 0.9999654330120931, "ai": 1.970801175076317e-05, "paraphrased": 1.4858976156165525e-05}, "interpretability_value": null, "interpretability_normalized_value": null, "interpretability_designation": null, "interpretability_alpha": null, "highlight_sentence_for_ai": false, "special_highlight_type": null}, {"generated_prob": 3.2534874054667996e-05, "sentence": "Luckily, I was able to rinse off the dirt/dog slobber since he has gotten to our steak twice now, cook it, and cut off tiny pieces for him to eat (with no salt or seasoning).", "perplexity": 0, "class_probabilities": {"human": 0.9999674651259454, "ai": 1.695984444515403e-05, "paraphrased": 1.557502960951397e-05}, "interpretability_value": null, "interpretability_normalized_value": null, "interpretability_designation": null, "interpretability_alpha": null, "highlight_sentence_for_ai": false, "special_highlight_type": null}, {"generated_prob": 3.721112922943448e-05, "sentence": "I don't know if there is anything sadder than a dog with a steak and no teeth to eat it with.", "perplexity": 0, "class_probabilities": {"human": 0.9999627888707706, "ai": 2.6615809000004853e-05, "paraphrased": 1.0595320229429627e-05}, "interpretability_value": null, "interpretability_normalized_value": null, "interpretability_designation": null, "interpretability_alpha": null, "highlight_sentence_for_ai": false, "special_highlight_type": null}], "class_probabilities": {"human": 0.9999917816162905, "ai": 8.218383709502331e-06, "mixed": 0}, "confidence_scores_raw": {"identity": {"human": 0.9999917816162905, "ai": 8.218383709502331e-06, "mixed": 0}}, "subclass": {}, "pageNumber": 0, "neatVersion": "4.4b", "version": "2026-03-30-base", "language": "en", "result_message": "Our detector is highly confident that the text is written entirely by a human.", "result_sub_message": null, "document_classification": "HUMAN_ONLY", "inputText": "My dog has no teeth. He had full mouth extractions about a year ago. I think he is pretty happy and I'm sure having them taken out made him feel much better, since when I adopted him, he had really severe tooth decay with exposed roots and heavy plaque. Right after he got them out, his energy level went way up, even for a senior pup. However there has been a bit of a problem since he is such a hood rat, he likes getting into my groceries. 

About once a week, I like to get us a steak to share. It's not very expensive, and usually comes with sides. It comes in an oven-ready tray so you can just pop it in the oven. However, my dog has learned how to get into the grocery bag, claw open the plastic wrap covering, and pull out the steak. 

Unfortunately for him (fortunately for me), since he has zero teeth, he has been unable to do anything about it once he gets the steak out of the packaging. Saddest dog ever. Luckily, I was able to rinse off the dirt/dog slobber since he has gotten to our steak twice now, cook it, and cut off tiny pieces for him to eat (with no salt or seasoning). I don't know if there is anything sadder than a dog with a steak and no teeth to eat it with.", "document_id": null}]}

