ass_probabilities": {"human": 0.07744702255916851, "ai": 0.9211420488499032, "paraphrased": 0.001410928590928195}, "interpretability_value": null, "interpretability_normalized_value": null, "interpretability_designation": null, "interpretability_alpha": null, "highlight_sentence_for_ai": true, "special_highlight_type": null}, {"generated_prob": 0.9337200243612418, "sentence": "With $10,000 investment, I will build a minimum viable product focused on cardiovasc", "perplexity": 0, "class_probabilities": {"human": 0.06627997563875816, "ai": 0.9322169152877745, "paraphrased": 0.0015031090734673013}, "interpretability_value": null, "interpretability_normalized_value": null, "interpretability_designation": null, "interpretability_alpha": null, "highlight_sentence_for_ai": true, "special_highlight_type": null}], "class_probabilities": {"human": 0.25966219939294527, "ai": 0.7403378006070548, "mixed": 0}, "confidence_scores_raw": {"identity": {"ai": 0.7403378006070548, "mixed": 0, "human": 0.25966219939294527}}, "subclass": {"ai": {"predicted_class": "pure_ai", "result_message": "", "confidence_score": 1, "confidence_category": "high", "class_probabilities": {"pure_ai": 1, "ai_paraphrased": 0}, "confidence_scores_raw": {"identity": {"pure_ai": 1, "ai_paraphrased": 0}}, "confidence_thresholds_raw": {"identity": {"ai_paraphrased": {"reject": 0.33, "low": 0.6, "medium": 0.8}, "pure_ai": {"reject": 0.33, "low": 0.6, "medium": 0.8}}}}}, "pageNumber": 0, "neatVersion": "4.4b", "version": "2026-03-30-base", "language": "en", "result_message": "Our detector is moderately confident that the text is written by AI.", "result_sub_message": null, "document_classification": "AI_ONLY", "inputText": "My dream business is to fill the market gap in personalized prevention using polygenic risk scores.Currently, healthcare is mostly reactive, while people only respond after disease happens. However, millions of health-conscious consumers and many clinics want tools that can predict risk earlier